// AUTO-GENERATED — do not edit manually
// Earth land mask: 250x250 tiles, bit-packed, base64
// 1=land, 0=ocean  (Mercator projection, lat ±85.0°)
export const EARTH_MASK_W = 250;
export const EARTH_MASK_H = 250;
export const EARTH_MASK_B64 = '';

// Continent starting regions: [id, tileX, tileY, label]
export const EARTH_REGIONS = [
  { id: 'north_america', tx: 55, ty: 89, label: 'North America' },
  { id: 'south_america', tx: 84, ty: 135, label: 'South America' },
  { id: 'europe', tx: 135, ty: 84, label: 'Europe' },
  { id: 'africa', tx: 138, ty: 125, label: 'Africa' },
  { id: 'asia', tx: 194, ty: 94, label: 'Asia' },
  { id: 'oceania', tx: 218, ty: 142, label: 'Oceania' },
];

// Decode the mask into a flat Uint8Array (1=land, 0=sea)
let _earthMask = null;
export function getEarthMask() {
  if (_earthMask) return _earthMask;
  const b64 = EARTH_MASK_B64;
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  _earthMask = new Uint8Array(EARTH_MASK_W * EARTH_MASK_H);
  for (let i = 0; i < _earthMask.length; i++) {
    _earthMask[i] = (bytes[i >> 3] >> (7 - (i & 7))) & 1;
  }
  return _earthMask;
}

// Is world tile (tx, ty) land?
export function isMaskLand(tx, ty) {
  if (tx < 0 || ty < 0 || tx >= EARTH_MASK_W || ty >= EARTH_MASK_H) return false;
  return getEarthMask()[ty * EARTH_MASK_W + tx] === 1;
}
